# test_safe_divide.py

import pytest

# Adjust this import to match where safe_divide is defined
# from your_module import safe_divide


def safe_divide(a: float, b: float, default: float = 0.0) -> float:
    try:
        return a / b
    except ZeroDivisionError:
        return default


@pytest.mark.parametrize(
    "a,b,expected",
    [
        (10, 2, 5),
        (9.0, 3.0, 3.0),
        (-10, 2, -5),
        (10, -2, -5),
        (-10, -2, 5),
        (0, 5, 0),
        (1, 4, 0.25),
    ],
)
def test_safe_divide_happy_path(a, b, expected):
    assert safe_divide(a, b) == expected


def test_safe_divide_with_float_precision():
    assert safe_divide(1, 3) == pytest.approx(0.3333333333)


def test_safe_divide_by_zero_returns_default_zero():
    assert safe_divide(10, 0) == 0.0


def test_safe_divide_by_zero_returns_custom_default():
    assert safe_divide(10, 0, default=-1.0) == -1.0


def test_safe_divide_zero_by_zero_returns_default():
    assert safe_divide(0, 0) == 0.0


def test_safe_divide_zero_by_zero_returns_custom_default():
    assert safe_divide(0, 0, default=999.0) == 999.0


@pytest.mark.parametrize(
    "a,b",
    [
        ("10", 2),
        (10, "2"),
        (None, 2),
        (10, None),
    ],
)
def test_safe_divide_invalid_types_raise_type_error(a, b):
    with pytest.raises(TypeError):
        safe_divide(a, b)


def test_safe_divide_default_can_be_none():
    assert safe_divide(10, 0, default=None) is None
